/**
 * OpenClaw Auto-Skill Extractor (inspired by OpenSpace)
 * Watches build journal for successful, reusable patterns.
 * When a pattern is used 2+ times across builds, auto-generates a SKILL.md draft.
 *
 * Usage:
 *   node auto-skill-extractor.js check    — check for extractable skills
 *   node auto-skill-extractor.js list     — list auto-generated skills
 *
 * Integration: Called from build-journal.js logBuild() on success.
 */

const fs = require('fs');
const path = require('path');

const config = require('./config');
const OPENCLAW = config.paths.root;
const SKILLS_DIR = path.join(OPENCLAW, 'skills');
const PATTERNS_INDEX = path.join(OPENCLAW, 'workspace', 'pattern-index.json');
const JOURNAL_PATH = path.join(OPENCLAW, 'build-journal.jsonl');
const EXTRACTED_LOG = path.join(OPENCLAW, 'workspace', 'extracted-skills.json');

const MIN_USES = 2; // Minimum times a pattern must appear before skill extraction

// ── Core API ────────────────────────────────────────────────────

/**
 * Check if a build record's patterns qualify for skill extraction.
 * Called from build-journal.js after a successful build.
 */
function checkForSkill(record) {
  if (!record || record.outcome !== 'success' || !record.patterns || record.patterns.length === 0) return;

  const index = readPatternIndex();
  const extracted = readExtractedLog();

  for (const pattern of record.patterns) {
    const key = pattern.toLowerCase().trim();
    const stats = index[key];
    if (!stats) continue;

    // Skip if already extracted
    if (extracted[key]) continue;

    // Check threshold
    if (stats.count >= MIN_USES) {
      const builds = getBuildsWithPattern(key);
      const skill = generateSkill(key, stats, builds);
      if (skill) {
        writeSkill(key, skill);
        markExtracted(key, skill.path);
        logToSharedContext(key, stats);
        console.log(`[auto-skill] Extracted skill: ${key} (${stats.count} uses across ${stats.projects.join(', ')})`);
      }
    }
  }
}

/**
 * Scan all patterns and extract any that qualify.
 */
function scanAndExtract() {
  const index = readPatternIndex();
  const extracted = readExtractedLog();
  const results = [];

  for (const [key, stats] of Object.entries(index)) {
    if (extracted[key]) continue;
    if (stats.count >= MIN_USES) {
      const builds = getBuildsWithPattern(key);
      const skill = generateSkill(key, stats, builds);
      if (skill) {
        writeSkill(key, skill);
        markExtracted(key, skill.path);
        results.push({ pattern: key, uses: stats.count, projects: stats.projects });
      }
    }
  }

  return results;
}

/**
 * List all auto-generated skills.
 */
function listAutoGenerated() {
  const extracted = readExtractedLog();
  return Object.entries(extracted).map(([key, data]) => ({
    pattern: key,
    path: data.path,
    extractedAt: data.extractedAt
  }));
}

// ── Skill Generation ────────────────────────────────────────────

function generateSkill(patternKey, stats, builds) {
  const name = patternKey.split(/[-_]/).map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
  const slug = patternKey.replace(/\s+/g, '-').toLowerCase();
  const skillDir = path.join(SKILLS_DIR, slug);

  // Don't overwrite existing manual skills
  if (fs.existsSync(path.join(skillDir, 'SKILL.md'))) {
    const existing = fs.readFileSync(path.join(skillDir, 'SKILL.md'), 'utf8');
    if (!existing.includes('autoGenerated: true')) return null; // Manual skill, skip
  }

  // Aggregate context from builds
  const allFiles = [...new Set(builds.flatMap(b => b.files || []))].slice(0, 10);
  const allSummaries = builds.map(b => b.summary).filter(Boolean);
  const allLearnings = builds.map(b => b.learnings).filter(Boolean);
  const latestBuild = builds[builds.length - 1];

  const content = `---
name: ${slug}
description: "${allSummaries[0] || `Pattern: ${name}`}"
metadata:
  openclaw:
    emoji: "🔧"
    skillKey: "${slug}"
    autoGenerated: true
    extractedAt: "${new Date().toISOString()}"
    sourceBuilds: ${stats.count}
    projects: [${stats.projects.map(p => `"${p}"`).join(', ')}]
---

# 🔧 ${name}

> Auto-extracted from ${stats.count} successful builds across ${stats.projects.join(', ')}.

## What

${allSummaries.map(s => `- ${s}`).join('\n')}

## When to Use

This pattern has been successfully applied in: ${stats.projects.join(', ')}.
${allLearnings.length > 0 ? '\n## Learnings\n\n' + allLearnings.map(l => `- ${l}`).join('\n') : ''}

## Key Files

${allFiles.map(f => `- \`${f}\``).join('\n') || '- No specific files recorded'}

## Build History

${builds.slice(-5).map(b => `- [${b.timestamp.split('T')[0]}] ${b.project}: ${b.summary}`).join('\n')}
`;

  return { content, path: path.join(skillDir, 'SKILL.md') };
}

function writeSkill(key, skill) {
  const dir = path.dirname(skill.path);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(skill.path, skill.content, 'utf8');
}

// ── Data Access ─────────────────────────────────────────────────

function readPatternIndex() {
  try {
    return JSON.parse(fs.readFileSync(PATTERNS_INDEX, 'utf8'));
  } catch {
    return {};
  }
}

function readExtractedLog() {
  try {
    return JSON.parse(fs.readFileSync(EXTRACTED_LOG, 'utf8'));
  } catch {
    return {};
  }
}

function markExtracted(key, skillPath) {
  const log = readExtractedLog();
  log[key] = { path: skillPath, extractedAt: new Date().toISOString() };
  const dir = path.dirname(EXTRACTED_LOG);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(EXTRACTED_LOG, JSON.stringify(log, null, 2), 'utf8');
}

function getBuildsWithPattern(patternKey) {
  try {
    const raw = fs.readFileSync(JOURNAL_PATH, 'utf8').trim();
    if (!raw) return [];
    return raw.split('\n')
      .map(line => { try { return JSON.parse(line); } catch { return null; } })
      .filter(b => b && b.patterns && b.patterns.some(p => p.toLowerCase().trim() === patternKey));
  } catch {
    return [];
  }
}

function logToSharedContext(key, stats) {
  try {
    const sc = require(path.join(OPENCLAW, 'shared-context'));
    sc.logEntry({
      platform: 'claude-code',
      type: 'task_completed',
      summary: `Auto-extracted skill: ${key} (${stats.count} uses, ${stats.projects.join('/')})`,
    });
  } catch {}
}

// ── CLI ─────────────────────────────────────────────────────────

if (require.main === module) {
  const cmd = process.argv[2];

  if (cmd === 'check') {
    const results = scanAndExtract();
    if (results.length === 0) {
      console.log('No new patterns qualify for skill extraction (need 2+ uses).');
      const index = readPatternIndex();
      const approaching = Object.entries(index).filter(([, v]) => v.count === 1);
      if (approaching.length > 0) {
        console.log(`\n${approaching.length} pattern(s) at 1 use (one more build to qualify):`);
        for (const [key, stats] of approaching) {
          console.log(`  ${key}: ${stats.projects.join(', ')}`);
        }
      }
    } else {
      console.log(`Extracted ${results.length} skill(s):`);
      for (const r of results) {
        console.log(`  ${r.pattern}: ${r.uses} uses across ${r.projects.join(', ')}`);
      }
    }
  } else if (cmd === 'list') {
    const skills = listAutoGenerated();
    if (skills.length === 0) {
      console.log('No auto-generated skills yet.');
    } else {
      console.log(`${skills.length} auto-generated skill(s):`);
      for (const s of skills) {
        console.log(`  ${s.pattern}: ${s.path} (${s.extractedAt.split('T')[0]})`);
      }
    }
  } else {
    console.log('Auto-Skill Extractor');
    console.log('  node auto-skill-extractor.js check  — extract qualifying patterns');
    console.log('  node auto-skill-extractor.js list   — list auto-generated skills');
  }
}

module.exports = { checkForSkill, scanAndExtract, listAutoGenerated };
